const items = $input.all();
const newsLines = [];

for (let i = 0; i < Math.min(items.length, 20); i++) {
  const item = items[i];
  const title = item.json.title || '제목 없음';
  const link = item.json.link || '';
  const pub = item.json.pubDate || item.json.isoDate || '';
  const summary = item.json.contentSnippet || item.json.summary || '';
  newsLines.push('[' + (i+1) + '] ' + title + '\n발행: ' + pub + '\n' + (summary ? '요약: ' + summary.slice(0, 300) : '') + '\n링크: ' + link);
}

const newsText = newsLines.join('\n\n');
return [{ json: { newsText: newsText, count: newsLines.length } }];
